const items = $input.all();
const validModes = ['simulation', 'execute'];
const validRiskLevels = ['low', 'medium', 'high'];
const validCreaStatuses = ['pending', 'approved', 'blocked', 'needs_human'];
const validDecisionStatuses = ['proposed', 'approved', 'blocked', 'halted', 'pending'];

const results = items.map(item => {
  const data = item.json;
  const errors = [];

  if (!data.request_id || typeof data.request_id !== 'string' || data.request_id.trim() === '') errors.push('request_id must be non-empty string');
  if (!data.source_workflow || typeof data.source_workflow !== 'string' || data.source_workflow.trim() === '') errors.push('source_workflow must be non-empty string');
  if (!data.department || typeof data.department !== 'string' || data.department.trim() === '') errors.push('department must be non-empty string');
  if (!data.task_type || typeof data.task_type !== 'string' || data.task_type.trim() === '') errors.push('task_type must be non-empty string');
  if (!validModes.includes(data.mode)) errors.push('mode must be simulation or execute');
  if (typeof data.confidence !== 'number' || isNaN(data.confidence) || data.confidence < 0 || data.confidence > 1) errors.push('confidence must be number between 0 and 1');
  if (!validRiskLevels.includes(data.risk_level)) errors.push('risk_level must be low, medium, or high');
  if (typeof data.founder_available !== 'boolean') errors.push('founder_available must be boolean');
  if (!validCreaStatuses.includes(data.crea_status)) errors.push('crea_status must be pending, approved, blocked, or needs_human');
  if (data.decision_status && !validDecisionStatuses.includes(data.decision_status)) errors.push('decision_status must be valid enum');
  if (typeof data.failure_count !== 'number' || !Number.isInteger(data.failure_count) || data.failure_count < 0) errors.push('failure_count must be integer >= 0');
  if (!data.audit || typeof data.audit !== 'object' || Array.isArray(data.audit)) errors.push('audit must be object');

  if (errors.length > 0) {
    return {
      json: {
        ...data,
        validation_passed: false,
        validation_errors: errors,
        execution_allowed: false,
        decision_status: 'blocked',
        reason: 'Invalid Universal Contract Schema: ' + errors.join('; ')
      }
    };
  }

  return {
    json: {
      ...data,
      validation_passed: true
    }
  };
});

return results;

const items = $input.all();

const results = items.map(item => {
  const data = item.json;

  if (!data.audit || !data.audit.original_contract_hash) {
    return {
      json: {
        ...data,
        locked_fields_valid: true,
        locked_fields_note: 'No original hash to verify - first pass'
      }
    };
  }

  const lockedFields = {
    request_id: data.request_id,
    mode: data.mode,
    confidence: data.confidence,
    risk_level: data.risk_level
  };

  const currentHash = (() => { const _s = JSON.stringify(lockedFields); let _h = 5381; for (let _i = 0; _i < _s.length; _i++) { _h = ((_h << 5) + _h + _s.charCodeAt(_i)) >>> 0; } return _h.toString(16); })();

  if (currentHash !== data.audit.original_contract_hash) {
    return {
      json: {
        ...data,
        locked_fields_valid: false,
        execution_allowed: false,
        decision_status: 'blocked',
        reason: 'Locked fields modified downstream — possible policy violation',
        hash_expected: data.audit.original_contract_hash,
        hash_actual: currentHash
      }
    };
  }

  return {
    json: {
      ...data,
      locked_fields_valid: true
    }
  };
});

return results;

const items = $input.all();
const results = items.map(item => {
  const data = item.json;
  const errors = [];

  if (!data.approval || typeof data.approval !== 'object') {
    errors.push('Approval payload missing');
  } else {
    if (data.approval.request_id !== data.request_id) {
      errors.push('Approval request_id mismatch');
    }
    if (data.approval.execution_allowed !== true) {
      errors.push('Approval does not explicitly allow execution');
    }
    if (!data.approval.timestamp) {
      errors.push('Approval timestamp missing');
    }
  }

  if (errors.length > 0) {
    return {
      json: {
        ...data,
        approval_valid: false,
        execution_allowed: false,
        decision_status: 'halted',
        reason: 'Invalid or missing Founder approval: ' + errors.join('; ')
      }
    };
  }

  return {
    json: {
      ...data,
      approval_valid: true
    }
  };
});

return results;

const items = $input.all();

const results = items.map(item => {
  const data = item.json;
  const sourceWorkflow = data.source_workflow;

  if (!sourceWorkflow) {
    return {
      json: {
        ...data,
        workflow_id_resolved: false,
        execution_allowed: false,
        decision_status: 'blocked',
        reason: 'Unable to safely freeze source workflow — ID missing'
      }
    };
  }

  const isNumeric = /^\d+$/.test(sourceWorkflow);
  const isUUID = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(sourceWorkflow);

  if (isNumeric || isUUID) {
    return {
      json: {
        ...data,
        workflow_id_resolved: true,
        resolved_workflow_id: sourceWorkflow
      }
    };
  }

  return {
    json: {
      ...data,
      workflow_id_resolved: false,
      execution_allowed: false,
      decision_status: 'blocked',
      reason: 'Unable to safely freeze source workflow — ID mismatch or invalid format'
    }
  };
});

return results;

const items = $input.all();

const results = items.map(item => {
  const data = item.json;
  const hasExecutionAllowed = 'execution_allowed' in data;
  const hasDecisionStatus = 'decision_status' in data && data.decision_status;
  const hasReason = 'reason' in data && data.reason;

  if (!hasExecutionAllowed || !hasDecisionStatus || !hasReason) {
    return {
      json: {
        ...data,
        execution_allowed: data.execution_allowed !== undefined ? data.execution_allowed : false,
        decision_status: data.decision_status || 'blocked',
        reason: data.reason || 'Incomplete enforcement path'
      }
    };
  }

  return { json: data };
});

return results;
